require "config.Define"

PlayerProperty = class("PlayerProperty", BaseProperty)

local exchangeRewardMap = {
    [Define.PayItemType.AutoWorkout] = "AutoWorkout",
    [Define.PayItemType.ConcealPower] = "ConcealPower",
    [Define.PayItemType.DoubleSpeed] = "DoubleSpeed",
    [Define.PayItemType.DoubleGold] = "DoubleGold",
    [Define.PayItemType.DoubleMuscle] = "DoubleMuscle",
}

function PlayerProperty:ctor()
    self.geneId = 0
    self.fitnessEquipId = 0
    self.unlockFitnessEquipId = 0
    self.advancedLevel = 0
    self.muscleMass = 0
    self.maxMuscleMass = 0
    self.muscleMassCoe = 0
    self.curHealth = 0
    self.maxHealth = 0
    self.canAttack = true --是否可以攻击
    self.canWorkout = true --是否可以锻炼
    self.catchEntityId = 0
    self.isAdvancing = false --是否是进阶状态
    self.isInit = false --是否初始化

    --付费功能
    self.payItemList = {}
    self.skinList = {}
    self.skinId = -1
    self.showSelectSkinDlg = true
    self.exchangeReward = self.exchangeReward or {}

    self:registerEvent(S2CLSPlayerPropertyInit, function(data)
        local builder = DataBuilder.new():fromData(data)
        self:init(builder)
    end)

    self:registerEvent(S2CLSHpUpdate, function(data)
        local builder = DataBuilder.new():fromData(data)
        self.curHealth = builder:getNumberParam("curHp")
        self.maxHealth = builder:getNumberParam("maxHp")
        HpChangeEvent:invoke(self.curHealth, self.maxHealth)
    end)

    self:registerEvent(S2CExchangeReward, function(data)
        local builder = DataBuilder.new():fromData(data)
        local propsType = builder:getParam("propsType")
        local leftTime = builder:getNumberParam("leftTime")
        self:changeExchangeRewardTime(propsType, leftTime)
        print("S2CExchangeReward", propsType, leftTime)
    end)

    self:registerEvent(S2CLSMpUpdate, function(data)
        local builder = DataBuilder.new():fromData(data)
        local maxMuscleMass = builder:getNumberParam("maxMp")
        local muscleMass = builder:getNumberParam("curMp")
        --HostApi.log(string.format("PlayerProperty:onMuscleMassChange %f %f", muscleMass, maxMuscleMass))
        self:onMuscleMassChange(muscleMass, maxMuscleMass)
    end)

    self:registerEvent(S2CLSFitnessEquip, function(data)
        local builder = DataBuilder.new():fromData(data)
        local curId = builder:getNumberParam("curId")
        local maxId = builder:getNumberParam("maxId")
        self:onFitnessEquipChange(curId, maxId)
    end)

    self:registerEvent(S2CLSGeneChange, function(data)
        local builder = DataBuilder.new():fromData(data)
        local geneId = builder:getNumberParam("geneId")
        local maxMuscleMass =builder:getNumberParam("maxMuscleMass")
        --print("S2CLSGeneChange " .. tostring(maxMuscleMass))
        self.geneId = geneId
        self.maxMuscleMass = maxMuscleMass
        --print("S2CLSGeneChange   "..maxMuscleMass)
        MuscleMassChangeEvent:invoke(self.muscleMass, self.maxMuscleMass, 0)
    end)

    self:registerEvent(S2CPayDataInit, function(data)
        self:onPayDataInit(data)
    end)
end

function PlayerProperty:hasPayItem(payItemType)
    return self.payItemList[tostring(payItemType)] ~= nil or self:hasExchangeReward(exchangeRewardMap[payItemType])
end

function PlayerProperty:hasExchangeReward(propsType)
    self:checkExchangeRewardTime(propsType)
    return self.exchangeReward[propsType] ~= nil
end

function PlayerProperty:checkExchangeRewardTime(propsType)
    local time = self.exchangeReward[propsType]
    if time and os.time() >= time then
        self.exchangeReward[propsType] = nil
    end
end

function PlayerProperty:changeExchangeRewardTime(propsType, time)
    self:checkExchangeRewardTime(propsType)
    self.exchangeReward[propsType] = self.exchangeReward[propsType] or os.time()
    self.exchangeReward[propsType] = self.exchangeReward[propsType] + time
end

function PlayerProperty:init(builder)
    self.geneId = builder:getNumberParam("geneId")
    self.advancedLevel = builder:getNumberParam("advancedLevel")
    self.muscleMass = builder:getNumberParam("muscleMass")
    self.maxMuscleMass = builder:getNumberParam("maxMuscleMass")
    --print("PlayerProperty:init " .. tostring(self.maxMuscleMass))
    self.muscleMassCoe = builder:getNumberParam("muscleMassCoe")
    --self.curHealth = builder:getNumberParam("curHealth")
    --self.baseHealth = builder:getNumberParam("baseHealth")
    --self.maxHealth = self:getMaxHealth()

    --HpChangeEvent:invoke(self.curHealth, self.maxHealth)
    MuscleMassChangeEvent:invoke(self.muscleMass, self.maxMuscleMass, 0)

    self:onFitnessEquipChange(builder:getNumberParam("fitnessEquipId"), builder:getNumberParam("unlockFitnessEquipId"))

    --print(string.format("PlayerProperty:init muscleMass:%s maxMuscleMass:%s curHealth:%s maxHealth:%s \
    --fitnessEquipId:%d unlockFitnessEquipId:%d", tostring(self.muscleMass), tostring(self.maxMuscleMass),
    --        tostring(self.curHealth), tostring(self.maxHealth), self.fitnessEquipId, self.unlockFitnessEquipId))
end

function PlayerProperty:onMuscleMassChange(muscleMass, maxMuscleMass)
    local inc = muscleMass - self.muscleMass
    self.muscleMass = muscleMass
    self.maxMuscleMass = maxMuscleMass
    MuscleMassChangeEvent:invoke(muscleMass, maxMuscleMass, inc)
    --print("MuscleMassChangeEvent ", tostring(self.muscleMass), tostring(self.maxMuscleMass))
end

function PlayerProperty:onFitnessEquipChange(curId, maxId)
    local last_fitnessEquipId = self.fitnessEquipId
    local last_unlockFitnessEquipId = self.unlockFitnessEquipId

    self.fitnessEquipId = curId
    self.unlockFitnessEquipId = maxId

    if self.fitnessEquipId ~= last_fitnessEquipId or self.unlockFitnessEquipId ~= last_unlockFitnessEquipId then
        FitnessEquipChangeEvent:invoke(self.fitnessEquipId, self.unlockFitnessEquipId)
    end
end

